const input = $input.first().json;
const fechaISO = input.fecha_preferida || input.fecha_hora;

// Helper para devolver error sin romper el workflow
function error(motivo) {
  return [{
    json: {
      valido: false,
      motivo
    }
  }];
}

// 1️⃣ Validar que exista la fecha
if (!fechaISO || typeof fechaISO !== 'string') {
  return error("No se recibió fecha para validar");
}

// 2️⃣ Parsear fecha ISO (YA incluye -03:00)
const fecha = new Date(fechaISO);

if (isNaN(fecha.getTime())) {
  return error("Formato de fecha inválido");
}

// 3️⃣ Validar año
if (fecha.getFullYear() !== 2026) {
  return error("Solo se aceptan reservas para el año 2026");
}

// 4️⃣ Validar que no sea pasada
const ahora = new Date();

if (fecha < ahora) {
  return error("No se pueden hacer reservas en fechas pasadas");
}

// 5️⃣ Extraer datos
// "2026-02-23T17:00:00.000-03:00"
const iso = fechaISO.toString();

const hora = Number(iso.substring(11, 13));
const minutos = Number(iso.substring(14, 16));
const horaDecimal = hora + minutos / 60;

const diaSemana = fecha.getDay(); // 0=domingo, 6=sábado

// 6️⃣ Reglas de negocio

// Domingo
if (diaSemana === 0) {
  return error("Los domingos no hay atención");
}

// Sábado: 10 a 12
if (diaSemana === 6) {
  if (horaDecimal < 10 || horaDecimal >= 12) {
    return error("Los sábados el horario de atención es de 10:00 a 12:00");
  }
}

// Lunes a viernes: 10 a 19
// Último inicio válido: 18:00
if (diaSemana >= 1 && diaSemana <= 5) {
  if (horaDecimal < 10) {
    return error("El horario de atención inicia a las 10:00");
  }

  if (horaDecimal >= 18) {
    return error(
      "El último horario para iniciar una clase es las 18:00 (las clases terminan a las 19:00)"
    );
  }
}

// 7️⃣ Todo OK
return [{
  json: {
    valido: true,
    motivo: "Horario válido",
    fecha_recibida: fechaISO,
    dia_semana: diaSemana,
    hora,
    minutos
  }
}];
